import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { ArrowLeft, ChevronUp } from 'lucide-react';
import './PageTemplate.css';

export default function PageTemplate({ title, image, metadata = [], children }) {
  const [tableOfContents, setTableOfContents] = useState([]);
  const [showScrollTop, setShowScrollTop] = useState(false);
  const [readingTime, setReadingTime] = useState(null);
  
  // Generate table of contents from h2 headings after component mounts and content is rendered
  useEffect(() => {
    // Wait for content to be rendered
    setTimeout(() => {
      const contentElement = document.querySelector('.page-content');
      if (!contentElement) return;
      
      // Find all h2 elements within the content
      const headings = Array.from(contentElement.querySelectorAll('h2'));
      
      // Generate TOC items
      const toc = headings.map(heading => {
        // Create an ID if it doesn't exist
        if (!heading.id) {
          const id = heading.textContent
            .toLowerCase()
            .replace(/[^\w\s]/g, '')
            .replace(/\s+/g, '-');
          heading.id = id;
        }
        
        return {
          id: heading.id,
          text: heading.textContent
        };
      });
      
      setTableOfContents(toc);
      
      // Calculate reading time
      if (contentElement) {
        const text = contentElement.textContent || '';
        const wordCount = text.split(/\s+/).filter(Boolean).length;
        const time = Math.ceil(wordCount / 200); // Average reading speed: 200 wpm
        setReadingTime(time);
      }
    }, 500); // Small delay to ensure content is rendered
  }, [children]);
  
  // Scroll to top button visibility
  useEffect(() => {
    const handleScroll = () => {
      setShowScrollTop(window.scrollY > 300);
    };
    
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);
  
  // Scroll to top function
  const scrollToTop = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <section className="page-template">
      <header className="page-header">
        <Link to="/#projects" className="back-link">
          <ArrowLeft size={20} />
          <span>Back to Projects</span>
        </Link>
        <div className="reading-time">
          {readingTime ? `${readingTime} min read` : ''}
        </div>
      </header>
      
      <h1 className="page-title">{title}</h1>

      {metadata.length > 0 && (
        <div className="project-meta" aria-label="Project metadata">
          {metadata.map((item) => (
            <article key={`${item.label}-${item.value}`} className="project-meta-item">
              <p className="meta-label">{item.label}</p>
              <p className="meta-value">{item.value}</p>
            </article>
          ))}
        </div>
      )}
      
      {image && (
        <div className="featured-image-container">
          <img src={image} alt={title} className="featured-image" />
        </div>
      )}
      
      <div className="content-layout">
        {tableOfContents.length > 0 && (
          <aside className="table-of-contents">
            <div className="toc-sticky">
              <h2>Contents</h2>
              <nav>
                <ul>
                  {tableOfContents.map((item) => (
                    <li key={item.id} className="toc-item">
                      <a href={`#${item.id}`}>{item.text}</a>
                    </li>
                  ))}
                </ul>
              </nav>
            </div>
          </aside>
        )}
        
        <article className="page-content">
          {children}
        </article>
      </div>
      
      <footer className="page-footer">
        <div className="case-study-cta">
          <h3>Looking for this type of execution?</h3>
          <p>I am open to ML engineering roles and freelance projects where research depth and production quality both matter.</p>
          <a href="mailto:marcossr2626@gmail.com" className="contact-cta-link">Contact Me</a>
        </div>
        
        <div className="page-navigation">
          <Link to="/#projects" className="back-navigation">
            <ArrowLeft size={20} />
            <span>Back to Projects</span>
          </Link>
        </div>
      </footer>
      
      {showScrollTop && (
        <button 
          className="scroll-to-top" 
          onClick={scrollToTop}
          aria-label="Scroll to top"
        >
          <ChevronUp size={24} />
        </button>
      )}
    </section>
  );
}